import{_ as i,o as a,c as e,a3 as t}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"MC卡到爆炸优化操作:linux-环境变量-DRI_PRIME是啥","description":"","frontmatter":{},"headers":[],"relativePath":"Linux系统/MC卡到爆炸优化操作linux-环境变量-DRI_PRIME.md","filePath":"Linux系统/MC卡到爆炸优化操作linux-环境变量-DRI_PRIME.md","lastUpdated":1779106755000}'),n={name:"Linux系统/MC卡到爆炸优化操作linux-环境变量-DRI_PRIME.md"};function l(o,s,r,h,p,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="mc卡到爆炸优化操作-linux-环境变量-dri-prime是啥" tabindex="-1">MC卡到爆炸优化操作:linux-环境变量-DRI_PRIME是啥 <a class="header-anchor" href="#mc卡到爆炸优化操作-linux-环境变量-dri-prime是啥" aria-label="Permalink to &quot;MC卡到爆炸优化操作:linux-环境变量-DRI_PRIME是啥&quot;">​</a></h1><p>我的笔记本玩MC很卡,双显卡有一个很垃圾的AMD显卡,后台使用了这个参数之后能流畅运行了.</p><blockquote><p>gemini生成</p></blockquote><p>在 Linux 系统中，<strong><code>DRI_PRIME</code></strong> 是一个非常实用的环境变量，主要用于<strong>配置了双显卡（通常是 Intel/AMD 核显 + AMD 独显）的笔记本或台式机上，用来指定由哪块显卡来运行某个特定的程序</strong>。</p><p>简单来说，它就是 Linux 下的“右键选择高性能显卡运行”。</p><hr><h2 id="核心原理-prime-技术" tabindex="-1">核心原理：PRIME 技术 <a class="header-anchor" href="#核心原理-prime-技术" aria-label="Permalink to &quot;核心原理：PRIME 技术&quot;">​</a></h2><p>在双显卡架构中，为了省电，系统默认会使用低功耗的<strong>集成显卡（核显）<strong>来渲染桌面和日常应用。而当你想玩游戏或运行 3D 渲染软件时，就需要调用高功耗的</strong>独立显卡（独显）</strong>。</p><p>Linux 通过 <strong>PRIME</strong> 技术来实现这种显卡之间的协同工作和画面复制。而 <code>DRI_PRIME</code> 环境变量就是这个技术的控制开关。</p><hr><h2 id="如何使用" tabindex="-1">如何使用？ <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用？&quot;">​</a></h2><p>它的用法非常简单，数值通常为 <code>0</code> 或 <code>1</code>：</p><ul><li><strong><code>DRI_PRIME=0</code></strong>：使用默认显卡（通常是核显）。</li><li><strong><code>DRI_PRIME=1</code></strong>：使用第二块显卡（通常是独显）。</li></ul><h3 id="_1-临时启动某个程序" tabindex="-1">1. 临时启动某个程序 <a class="header-anchor" href="#_1-临时启动某个程序" aria-label="Permalink to &quot;1. 临时启动某个程序&quot;">​</a></h3><p>如果你想用独显运行某个游戏（比如 Steam 里的游戏）或软件，可以在终端里这样启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DRI_PRIME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> glxgears</span></span></code></pre></div><p>或者启动 Steam 游戏时，在游戏的“启动选项”中加入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DRI_PRIME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> %command%</span></span></code></pre></div><h3 id="_2-验证是否生效" tabindex="-1">2. 验证是否生效 <a class="header-anchor" href="#_2-验证是否生效" aria-label="Permalink to &quot;2. 验证是否生效&quot;">​</a></h3><p>你可以通过 <code>glxinfo</code> 命令来测试它是否成功切换了显卡：</p><ul><li><strong>查看默认显卡（核显）：</strong></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">glxinfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;OpenGL renderer&quot;</span></span></code></pre></div><p><em>输出可能类似于：Device: AMD Radeon Graphics (renoir, ...)</em></p><ul><li><strong>查看指定后的显卡（独显）：</strong></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    DRI_PRIME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> glxinfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;OpenGL renderer&quot;</span></span></code></pre></div><pre><code>*输出应该会变成你的独立显卡，比如：AMD Radeon RX 6600M*
</code></pre><hr><h2 id="⚠️-注意事项与局限性" tabindex="-1">⚠️ 注意事项与局限性 <a class="header-anchor" href="#⚠️-注意事项与局限性" aria-label="Permalink to &quot;⚠️ 注意事项与局限性&quot;">​</a></h2><ol><li><strong>主要支持开源驱动</strong>：<code>DRI_PRIME</code> 完美适用于 <strong>Mesa 开源驱动链</strong>（即 Intel 核显 + AMD 独显，或者 AMD 核显 + AMD 独显）。</li><li><strong>NVIDIA 独显用户</strong>：如果你使用的是 NVIDIA 官方闭源驱动（专有驱动），通常不使用 <code>DRI_PRIME</code>，而是使用 NVIDIA 自家的 <code>__NV_PRIME_RENDER_OFFLOAD=1</code> 和 <code>__GLX_VENDOR_LIBRARY_NAME=nvidia</code> 环境变量，或者使用 <code>prime-run</code> 脚本。</li><li><strong>显卡编号</strong>：在极少数有多块显卡的复杂系统上，<code>DRI_PRIME</code> 的值可以是 <code>2</code> 或更高，代表系统中的第三块显卡。你可以通过 <code>xrandr --listproviders</code> 命令来查看系统中的显卡列表和编号。</li></ol>`,29)])])}const g=i(n,[["render",l]]);export{k as __pageData,g as default};
